using System;
using System.Data.SqlClient;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using System.Collections.Generic;
using System.Text;

namespace SecureReportingAPI
{
    public static class ReportingFunction
    {
        [FunctionName("QueryReports")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
            ILogger log)
        {
            log.LogInformation("Processing reporting query request.");

            string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");

            try
            {
                var allowedColumns = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
                {
                    "Id", "Name", "Category", "Status", "CreatedDate", "Amount", "Region"
                };

                var allowedOperators = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
                {
                    "=", ">", "<", ">=", "<=", "LIKE"
                };

                var filters = new List<FilterCondition>();
                
                foreach (var param in req.Query)
                {
                    if (param.Key.Equals("orderBy", StringComparison.OrdinalIgnoreCase) || 
                        param.Key.Equals("limit", StringComparison.OrdinalIgnoreCase))
                        continue;

                    string[] parts = param.Key.Split('_');
                    if (parts.Length < 2)
                        continue;

                    string column = parts[0];
                    string operatorStr = parts[1];

                    if (!allowedColumns.Contains(column))
                    {
                        log.LogWarning($"Invalid column name attempted: {column}");
                        continue;
                    }

                    if (!allowedOperators.Contains(operatorStr))
                    {
                        log.LogWarning($"Invalid operator attempted: {operatorStr}");
                        continue;
                    }

                    filters.Add(new FilterCondition
                    {
                        Column = column,
                        Operator = operatorStr,
                        Value = param.Value.ToString()
                    });
                }

                string orderBy = req.Query["orderBy"].ToString();
                if (!string.IsNullOrEmpty(orderBy) && !allowedColumns.Contains(orderBy))
                {
                    orderBy = "Id";
                }
                else if (string.IsNullOrEmpty(orderBy))
                {
                    orderBy = "Id";
                }

                int limit = 100;
                if (int.TryParse(req.Query["limit"], out int parsedLimit))
                {
                    limit = Math.Min(Math.Max(parsedLimit, 1), 1000);
                }

                var results = await ExecuteSecureQuery(connectionString, filters, orderBy, limit, log);

                return new OkObjectResult(new
                {
                    count = results.Count,
                    data = results
                });
            }
            catch (Exception ex)
            {
                log.LogError(ex, "Error executing query");
                return new StatusCodeResult(500);
            }
        }

        private static async Task<List<Dictionary<string, object>>> ExecuteSecureQuery(
            string connectionString,
            List<FilterCondition> filters,
            string orderBy,
            int limit,
            ILogger log)
        {
            var results = new List<Dictionary<string, object>>();

            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();

                var queryBuilder = new StringBuilder("SELECT TOP (@Limit) * FROM Reports");
                var parameters = new List<SqlParameter>();
                
                parameters.Add(new SqlParameter("@Limit", limit));

                if (filters.Count > 0)
                {
                    queryBuilder.Append(" WHERE ");
                    for (int i = 0; i < filters.Count; i++)
                    {
                        if (i > 0)
                            queryBuilder.Append(" AND ");

                        var filter = filters[i];
                        string paramName = $"@Param{i}";

                        queryBuilder.Append($"[{filter.Column}] {filter.Operator} ");

                        if (filter.Operator.Equals("LIKE", StringComparison.OrdinalIgnoreCase))
                        {
                            queryBuilder.Append(paramName);
                            parameters.Add(new SqlParameter(paramName, $"%{filter.Value}%"));
                        }
                        else
                        {
                            queryBuilder.Append(paramName);
                            parameters.Add(new SqlParameter(paramName, filter.Value));
                        }
                    }
                }

                queryBuilder.Append($" ORDER BY [{orderBy}]");

                using (var command = new SqlCommand(queryBuilder.ToString(), connection))
                {
                    command.Parameters.AddRange(parameters.ToArray());

                    log.LogInformation($"Executing query: {queryBuilder}");

                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                row[reader.GetName(i)] = reader.IsDBNull(i) ? null : reader.GetValue(i);
                            }
                            results.Add(row);
                        }
                    }
                }
            }

            return results;
        }

        private class FilterCondition
